import React, { useState } from 'react';

import ResumeService
from '../services/ResumeService';

function ResumeForm() {

  const [resume, setResume] = useState({

    fullName: '',
    email: '',
    phone: '',
    github: '',
    linkedin: '',
    portfolio: '',
    summary: '',

    skills: [''],
    education: [''],
    experience: [''],
    projects: ['']

  });

  // NORMAL INPUTS

  const handleChange = (e) => {

    setResume({

      ...resume,
      [e.target.name]: e.target.value

    });
  };

  // DYNAMIC SECTION CHANGE

  const handleArrayChange = (
    index,
    field,
    value
  ) => {

    const updated =
      [...resume[field]];

    updated[index] = value;

    setResume({

      ...resume,
      [field]: updated

    });
  };

  // ADD NEW FIELD

  const addField = (field) => {

    setResume({

      ...resume,

      [field]: [

        ...resume[field],
        ''

      ]

    });
  };

  const removeField = (
  field,
  index
) => {

  const updated =
    [...resume[field]];

  updated.splice(index, 1);

  setResume({

    ...resume,

    [field]: updated

  });
};

  // SUBMIT

  const handleSubmit = async (e) => {

    e.preventDefault();

    try {

      const formattedResume = {

        ...resume,

        skills:
          resume.skills.join(', '),

        education:
          resume.education.join('\n'),

        experience:
          resume.experience.join('\n'),

        projects:
          resume.projects.join('\n')

      };

      await ResumeService
        .saveResume(formattedResume);

      alert(
        'Resume Saved Successfully'
      );

    } catch (error) {

      console.log(error);

      alert('Error Saving Resume');
    }
  };

  return (

    <div className="container mt-5">

      <div className="card shadow p-5">

        <h1 className="text-center mb-5">

          Create Resume

        </h1>

        <form onSubmit={handleSubmit}>

          {/* BASIC INFO */}

          <input
            type="text"
            name="fullName"
            placeholder="Full Name"
            className="form-control mb-3"
            onChange={handleChange}
          />

          <input
            type="email"
            name="email"
            placeholder="Email"
            className="form-control mb-3"
            onChange={handleChange}
          />

          <input
            type="text"
            name="phone"
            placeholder="Phone"
            className="form-control mb-3"
            onChange={handleChange}
          />

          <input
  type="text"
  name="github"
  placeholder="GitHub URL"
  className="form-control mb-3"
  onChange={handleChange}
/>

<input
  type="text"
  name="linkedin"
  placeholder="LinkedIn URL"
  className="form-control mb-3"
  onChange={handleChange}
/>

<input
  type="text"
  name="portfolio"
  placeholder="Portfolio URL"
  className="form-control mb-3"
  onChange={handleChange}
/>

          <textarea
            name="summary"
            placeholder="Professional Summary"
            className="form-control mb-4"
            onChange={handleChange}
          ></textarea>

          {/* SKILLS */}

          <h4>Skills</h4>

{
  resume.skills.map((skill, index) => (

    <div
      className="d-flex mb-2"
      key={index}
    >

      <input
        type="text"
        value={skill}
        placeholder="Skill"
        className="form-control me-2"
        onChange={(e) =>
          handleArrayChange(
            index,
            'skills',
            e.target.value
          )
        }
      />

      <button
        type="button"
        className="btn btn-danger"
        onClick={() =>
          removeField(
            'skills',
            index
          )
        }
      >

        Remove

      </button>

    </div>

  ))
}

<button
  type="button"
  className="btn btn-primary mb-4"
  onClick={() =>
    addField('skills')
  }
>

  Add Skill

</button>

          {/* EDUCATION */}

          <h4>Education</h4>

          {
            resume.education.map((edu, index) => (

              <textarea
                key={index}
                value={edu}
                placeholder="Education"
                className="form-control mb-2"
                onChange={(e) =>
                  handleArrayChange(
                    index,
                    'education',
                    e.target.value
                  )
                }
              ></textarea>

            ))
          }

          <button
            type="button"
            className="btn btn-primary mb-4"
            onClick={() =>
              addField('education')
            }
          >

            Add Education

          </button>

          {/* EXPERIENCE */}

          <h4>Experience</h4>

          {
            resume.experience.map((exp, index) => (

              <textarea
                key={index}
                value={exp}
                placeholder="Experience"
                className="form-control mb-2"
                onChange={(e) =>
                  handleArrayChange(
                    index,
                    'experience',
                    e.target.value
                  )
                }
              ></textarea>

            ))
          }

          <button
            type="button"
            className="btn btn-primary mb-4"
            onClick={() =>
              addField('experience')
            }
          >

            Add Experience

          </button>

          {/* PROJECTS */}

          <h4>Projects</h4>

          {
            resume.projects.map((project, index) => (

              <textarea
                key={index}
                value={project}
                placeholder="Project"
                className="form-control mb-2"
                onChange={(e) =>
                  handleArrayChange(
                    index,
                    'projects',
                    e.target.value
                  )
                }
              ></textarea>

            ))
          }

          <button
            type="button"
            className="btn btn-primary mb-4"
            onClick={() =>
              addField('projects')
            }
          >

            Add Project

          </button>

          {/* SAVE */}

          <button
            className="btn btn-success w-100"
          >

            Save Resume

          </button>

        </form>

      </div>

    </div>
  );
}

export default ResumeForm;
